mapper.select:
SELECT
FROM alerts
ORDER BY triggered_at DESC LIMIT #{limit} OFFSET #{offset}

mapper.insert:
INSERT INTO alerts (
    alert_id, alert_type, severity, status,
    vehicle_plate, cargo_id, title, summary, description,
    lat, lng, triggered_at
) VALUES (
    #{alertId}, #{alertType}, #{severity}, #{status},
    #{vehiclePlate}, #{cargoId}, #{title}, #{summary}, #{description},
    #{lat}, #{lng}, #{triggeredAt}
)

mapper.select:
SELECT COUNT(1)
FROM alerts
WHERE vehicle_plate = #{vehiclePlate}
AND alert_type = #{alertType}
AND status IN ('PENDING', 'ACKNOWLEDGED')
